import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        List<List<int[]>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long start = edge[2];
            long end = edge[3];
            adj.get((int) u).add(new int[]{(int) v, (int) start, (int) end});
        }

        long[] dist = new long[(int) n];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0});

        while (!pq.isEmpty()) {
            long[] curr = pq.poll();
            long current_time = curr[0];
            int u = curr[1];

            if (u == (int) (n - 1)) {
                return current_time;
            }

            if (current_time > dist[u]) {
                continue;
            }

            for (int[] edge : adj.get(u)) {
                int v = edge[0];
                int start = edge[1];
                int end = edge[2];

                long s = Math.max(current_time, start);
                if (s <= end) {
                    long new_time = s + 1;
                    if (new_time < dist[v]) {
                        dist[v] = new_time;
                        pq.offer(new long[]{new_time, v});
                    }
                }
            }
        }

        return -1;
    }
}
